import{_ as e,o as t,c as o,Q as i}from"./chunks/framework.c4d6cd72.js";const f=JSON.parse('{"title":"Release Notes","description":"","frontmatter":{"sidebar":false,"prev":false,"next":false},"headers":[],"relativePath":"release-notes/index.md","filePath":"release-notes/index.md"}'),n={name:"release-notes/index.md"},a=i('<h1 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h1><h2 id="version-1-2-2023-12-14" tabindex="-1">Version 1.2 (2023-12-14) <a class="header-anchor" href="#version-1-2-2023-12-14" aria-label="Permalink to &quot;Version 1.2 (2023-12-14)&quot;">​</a></h2><h3 id="main-changes" tabindex="-1">Main Changes <a class="header-anchor" href="#main-changes" aria-label="Permalink to &quot;Main Changes&quot;">​</a></h3><ul><li><p>When submitting a contribution or a flag, the API response now displays the reward for the said submission in tokens.</p><blockquote><p>Documented here:<br><a href="./../api-specification/contribution-controller/retrieving-top-contributions.html">API Specification &gt; Retrieving top contributions</a> — <code>confidence-score</code> added to <strong>Parameters</strong> and <strong>Output/response structure</strong> updated.</p></blockquote></li><li><p>When retrieving top contributions, the API response now displays additional information.</p><blockquote><p>Documented here:<br><a href="./../overview/contributions.html#api-requests-data-structure">Overview &gt; Contributions</a> — <strong>API requests data structure</strong> updated with <code>flagger</code>, <code>self</code>, <code>old</code>, <code>new</code> and <code>creditsSpent</code> fields.<br><a href="./../api-specification/contribution-controller/retrieving-top-contributions.html">API Specification &gt; Retrieving top contributions</a> — <strong>Output/response structure</strong> updated.</p></blockquote></li><li><p>Contributions on the blockchain now have a <code>flagger</code> value that displays the ID of a peer that flagged the contribution if it has been flagged.</p><blockquote><p>Documented here:<br><a href="./../overview/contributions.html#api-requests-data-structure">Overview &gt; Contributions</a> — <strong>Flagging contributions</strong> and <strong>API requests data structure</strong> updated.</p></blockquote></li><li><p>Added functionality related to the confidence index, a value between 1 and 100 that represents how confident the system is that a contributed fraud event is legitimate.</p><blockquote><p>Documented here:<br><a href="./../overview/tokenomics.html#confidence-index">Overview &gt; Tokenomics</a> — <strong>Confidence Index</strong> subtopic added.<br><a href="./../api-specification/contribution-controller/retrieving-top-contributions.html">API Specification &gt; Retrieving top contributions</a> — <code>confidence-score</code> added to <strong>Parameters</strong> and <strong>Output/response structure</strong> updated.</p></blockquote></li></ul><h3 id="other-improvements" tabindex="-1">Other Improvements <a class="header-anchor" href="#other-improvements" aria-label="Permalink to &quot;Other Improvements&quot;">​</a></h3><ul><li><p>Performed an audit of the interservice communication safety, fixed known security-related vulnerabilities, updated the implemented third-party dependencies.</p></li><li><p>Indexed data on the network, enhancing the overall performance of the search engine that retrieves stored contributions.</p></li><li><p>Refactored and optimized the code structure of the query engine that can retrieve all data of any specific type.</p></li></ul><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><p>Fixed a bug where leftover data with peer details remained on the network after a peer had been deleted; this caused a new peer account to be corrupted in case it was registered again with the same credentials, as well as potential issues with other peer data getting corrupted.</p></li><li><p>Fixed a bug that allowed users to find out the subscription type of any other peer.</p></li><li><p>Fixed a bug with call processing timeouts being inconsistent.</p></li></ul><h2 id="version-1-1-2023-04-27" tabindex="-1">Version 1.1 (2023-04-27) <a class="header-anchor" href="#version-1-1-2023-04-27" aria-label="Permalink to &quot;Version 1.1 (2023-04-27)&quot;">​</a></h2><p>Initial public version released with the functionality documented in our <a href="./../">Guide</a>.</p><h2 id="version-1-0-2022-12-12" tabindex="-1">Version 1.0 (2022-12-12) <a class="header-anchor" href="#version-1-0-2022-12-12" aria-label="Permalink to &quot;Version 1.0 (2022-12-12)&quot;">​</a></h2><p>Internal version not released to public.</p>',12),r=[a];function s(d,c,l,u,h,p){return t(),o("div",null,r)}const g=e(n,[["render",s]]);export{f as __pageData,g as default};
